def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    priority += np.tanh(term) * np.sin(ratio * b / (a + 1)) * a * 0.4
            priority += np.exp(ratio - 8) * np.sin(ratio * 1.5) * np.cos(ratio * 0.7) * 2.2
        elif 5 < ratio <= 8:
            temp = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 1)
                    temp += np.sin(val) * 1.6 - np.tanh(val / (p + q))
            priority = temp + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 3 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 2.1) * np.sin(r * ratio * 0.9)
            priority = s * np.cos(5 * ratio) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2.3
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.8) / (m ** 2 + 0.3)
        elif 1 <= ratio < 3:
            s = 0
            for n in range(1, 20):
                s += ((3 - ratio) ** n) / (n ** 1.7 + 0.2)
            if cap < item * 1.3:
                penalty = np.sqrt(item / (cap + 0.3)) * 5.5
            else:
                penalty = np.cos(15 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.08))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i) * ((ratio - 1) ** k) / (k + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for x in range(1, 18):
                s += ((1 - ratio) ** x) / (x * 5 + 1)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(cap + 5) * 1.7
            else:
                priority /= (np.sqrt(cap + 2) + 3)
            for y in range(1, 8):
                priority += ((1 - ratio) ** y) * np.cos(y * item * 1.5) * 0.9
            if cap < item * 0.75:
                priority += np.log1p(item * cap * 0.8) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for z in range(1, 14):
                s += ((0.5 - ratio) ** z) / (z * 3.8) * np.sin(z * ratio * 2.5)
            priority = s + 1 / (cap + 4)
            if int(item * 1.8) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            for w in range(1, 9):
                priority += ((0.5 - ratio) ** w) / (w * 4) * np.cos(item * w * 1.3)
            if cap < item * 0.22:
                priority += np.log1p(item * cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.2 - ratio) ** v) / (v * 6) * np.cos(v * item * 0.95)
            priority = s + 3 / (cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if cap < item * 0.18:
                priority += np.log1p(item * cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5.5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.82)
        if cap < item * 0.55:
            priority += np.log1p(item ** 2 * cap) * 6.2
        elif cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.72
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.72
        if int(item * cap) % 3 == 0:
            priority += np.sin(ratio * item * cap * 0.4) * 1.1
        else:
            priority -= np.cos(ratio * item * cap * 0.4) * 1.1
        priorities[i] = priority
    return priorities
